INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Droplets (Virtual Machines)$q$, $q$Shared-CPU and dedicated-CPU Linux virtual machines with SSD storage, billed hourly or monthly, that can be resized or snapshotted on demand.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$DigitalOcean Kubernetes (DOKS)$q$, $q$A managed Kubernetes control plane for deploying and scaling containerized applications without operating the control plane yourself.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$App Platform$q$, $q$A fully managed platform-as-a-service that builds and deploys apps directly from a Git repository, handling scaling, TLS, and zero-downtime deploys.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Spaces Object Storage$q$, $q$S3-compatible object storage with a built-in CDN option for serving static assets, backups, and media at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Managed Databases$q$, $q$Fully managed PostgreSQL, MySQL, and Redis- and MongoDB-compatible database clusters with automated backups and failover.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Volumes Block Storage$q$, $q$Attachable, resizable SSD block storage that can be moved between Droplets independently of the underlying VM.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Load Balancers and VPC Networking$q$, $q$Managed load balancers and private virtual networking (VPC) for distributing traffic and isolating internal service communication.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Marketplace One-Click Apps$q$, $q$Pre-configured application and stack templates (WordPress, Docker, LAMP, and more) that deploy onto a Droplet in a few clicks.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$GPU Droplets and Gradient AI Platform$q$, $q$GPU-backed compute instances and an AI/ML platform, built in part on the acquired Paperspace technology, for training and running models.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$API and CLI (doctl)$q$, $q$A comprehensive REST API and official command-line tool for scripting and automating infrastructure management.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Simple, predictable pricing pages compared to the itemized billing of AWS, Azure, and GCP$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Strong documentation and a large public tutorial library covering general server administration, not just DigitalOcean-specific topics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Fast, developer-friendly onboarding — a Droplet or App Platform deployment can be running within minutes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Hourly billing on compute means short-lived workloads aren't forced into full monthly commitments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Broad enough product set (compute, Kubernetes, storage, databases, PaaS) to run most standard web applications without leaving the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Smaller global region footprint than AWS, Azure, or Google Cloud, which can matter for latency-sensitive or highly regulated deployments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Fewer specialized managed services (advanced data warehousing, extensive first-party AI/ML tooling, niche compliance offerings) than the hyperscalers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Support responsiveness and depth on lower-tier plans can lag behind what larger enterprise cloud contracts provide$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Usage-based add-ons like bandwidth overages, backups, and load balancers can still make monthly bills less flat than the headline per-Droplet pricing suggests$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Less mature multi-cloud and enterprise governance tooling than AWS Organizations or Azure's enterprise agreements, which can be a limiting factor for large organizations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$What is DigitalOcean used for?$q$, $q$DigitalOcean is used to host and run web applications, APIs, databases, and containerized workloads. Common uses include running virtual machines (Droplets) for web servers, deploying apps through App Platform without managing servers directly, running Kubernetes clusters, and storing files or backups in Spaces object storage.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$How does DigitalOcean pricing work?$q$, $q$DigitalOcean pricing is usage-based. Droplets start at $4/month for a small shared-CPU instance and can be billed hourly or monthly; other services like Spaces, Managed Databases, and Load Balancers have their own flat or usage-based rates, and new accounts are typically eligible for a free trial credit.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Is DigitalOcean good for beginners?$q$, $q$Yes. DigitalOcean is widely regarded as one of the more approachable cloud platforms for developers who are new to managing servers, thanks to its simplified control panel, one-click Marketplace app templates, and an extensive library of community tutorials covering common setup and troubleshooting tasks.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$How does DigitalOcean compare to AWS, Azure, and Google Cloud?$q$, $q$DigitalOcean offers a smaller, simpler set of core infrastructure products with more predictable pricing, while AWS, Azure, and Google Cloud offer far larger service catalogs, more regions, and deeper enterprise and compliance tooling. Teams that want simplicity and cost predictability often prefer DigitalOcean; teams needing the broadest service set usually choose a hyperscaler.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Does DigitalOcean support Kubernetes and containers?$q$, $q$Yes. DigitalOcean Kubernetes (DOKS) provides a managed Kubernetes control plane, and the platform also offers a Container Registry for storing images, App Platform for container-based deployments without managing Kubernetes directly, and GPU Droplets for compute-intensive containerized workloads.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Hosting web applications and APIs$q$, $q$Deploy and run production web applications or backend APIs on Droplets or App Platform with straightforward scaling and monitoring.$q$, $q$Developers and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Running managed Kubernetes clusters$q$, $q$Use DigitalOcean Kubernetes to orchestrate containerized microservices without operating the Kubernetes control plane in-house.$q$, $q$DevOps engineers and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Startup and MVP infrastructure$q$, $q$Stand up cost-predictable infrastructure for an early-stage product, using App Platform, Managed Databases, and Spaces to avoid a large upfront DevOps investment.$q$, $q$Startup founders and indie developers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Client and agency hosting$q$, $q$Manage hosting for multiple client websites and applications using Marketplace one-click templates, snapshots, and simple per-Droplet billing.$q$, $q$Web development agencies and freelancers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Basic Droplets$q$, $q$From $4/month$q$, $q$Monthly (hourly billing also available)$q$, $q$["Shared-CPU virtual machines","SSD storage included","Resizable and snapshot-able","Pay-by-the-hour option for short-lived workloads"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$App Platform$q$, $q$Free static tier; paid plans from approximately $5/month$q$, $q$Monthly$q$, $q$["Deploy directly from a Git repository","Automatic builds and TLS certificates","Autoscaling for web services","Managed zero-downtime deploys"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$DigitalOcean Kubernetes (DOKS)$q$, $q$Usage-based (control plane plus per-node Droplet pricing)$q$, $q$Monthly (hourly billing available)$q$, $q$["Managed Kubernetes control plane","Auto-scaling node pools","Integrated load balancers and container registry","Standard Kubernetes API compatibility"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$Enterprise / Custom$q$, $q$Custom / Contact sales$q$, $q$Custom$q$, $q$["Volume-based discounts","Dedicated account support","Advanced security and compliance options","Tailored architecture guidance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DigitalOcean is a cloud infrastructure provider founded in 2011 that built its reputation on making server hosting simple and predictable at a time when Amazon Web Services and other hyperscalers were seen as powerful but overwhelming. It is a publicly traded company (NYSE: DOCN) headquartered in New York.$q$, $q$The platform's core offerings include Droplets (virtual machines), DigitalOcean Kubernetes (DOKS) for container orchestration, App Platform as a fully managed PaaS, Spaces for S3-compatible object storage, Managed Databases, block storage Volumes, Load Balancers, a private VPC networking layer, and a Marketplace of one-click application templates.$q$, $q$Where AWS, Azure, and Google Cloud sell hundreds of interlocking services with layered pricing, DigitalOcean deliberately keeps its catalog smaller and its pricing pages easy to read, positioning itself as the cloud for developers, startups, and small-to-midsize businesses who want production-grade infrastructure without a dedicated cloud operations team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$who-digitalocean-is-for$q$, $q$Who DigitalOcean Is For$q$, 2, ARRAY[$q$DigitalOcean is aimed squarely at software developers, indie hackers, and small engineering teams who need to deploy web applications, APIs, and databases quickly without wading through a large cloud provider's configuration options and service catalog.$q$, $q$Startups and growing SaaS companies that have outgrown shared hosting but don't yet need enterprise-scale multi-region architecture find DigitalOcean's straightforward Droplet and App Platform pricing easier to forecast than the itemized, usage-heavy bills typical of the big three clouds.$q$, $q$Agencies and freelance developers who manage infrastructure for multiple clients also gravitate to DigitalOcean because the control panel, API, and documentation are built around getting a server or app running in minutes, and the Marketplace one-click templates cover common stacks like WordPress, LAMP, and Docker.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex compliance requirements, deep multi-cloud strategies, or a need for the full breadth of managed services (advanced AI/ML infrastructure at massive scale, specialized data warehousing, dozens of region choices) will generally find AWS, Azure, or Google Cloud a better fit than DigitalOcean's leaner catalog.$q$, $q$Teams that require extensive enterprise support tiers, deep third-party integration marketplaces, or highly specialized compliance certifications for regulated industries may find DigitalOcean's offering thinner than what the hyperscalers provide out of the box.$q$, $q$Organizations that have already invested heavily in another cloud's proprietary services, or that need very fine-grained global infrastructure footprints across many dozens of regions, will likely find migrating to DigitalOcean's smaller region list a step backward rather than a simplification.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Droplets are DigitalOcean's virtual machine product, available as shared-CPU or dedicated-CPU instances with SSD storage, and billed hourly or monthly so short-lived workloads don't have to commit to a full month of usage.$q$, $q$DigitalOcean Kubernetes (DOKS) provides a managed control plane for running containerized workloads, while App Platform abstracts servers entirely, letting developers deploy directly from a Git repository and have builds, scaling, and TLS certificates handled automatically.$q$, $q$Beyond compute, the platform rounds out with Spaces object storage, Managed Databases (PostgreSQL, MySQL, Redis-compatible, and MongoDB-compatible options), Volumes block storage, Load Balancers, a private VPC, a Container Registry, and GPU-backed Droplets and the Gradient AI platform (built in part on the acquired Paperspace technology) for machine learning workloads.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', $q$digitalocean-experience$q$, $q$The DigitalOcean Experience$q$, 2, ARRAY[$q$The day-to-day experience of using DigitalOcean centers on a clean, uncluttered control panel and a well-documented REST API and CLI (doctl) that make it straightforward to spin up, resize, snapshot, or destroy infrastructure without reading pages of configuration reference.$q$, $q$Documentation is a genuine strength: the DigitalOcean Community tutorials library covers a huge range of server administration and application deployment topics and is frequently cited by developers even when they aren't hosting on DigitalOcean, which reinforces the brand's developer-friendly reputation.$q$, $q$Billing feels more predictable than typical hyperscaler invoices because most products list a flat hourly or monthly rate up front, though usage-based add-ons like bandwidth overages, backups, and load balancers still mean the final bill can vary with actual consumption.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba98f35c-82a6-4687-8668-be82a6c21e8d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$PDF Editing$q$, $q$Add and edit text, draw, highlight, and insert images directly on a PDF page in the browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$E-Signature & Sign Requests$q$, $q$Sign documents yourself or send sign requests to others, with status tracking as recipients complete them.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Google Drive & Gmail Integration$q$, $q$Open, edit, and save PDFs directly from Gmail and Google Drive without downloading a local copy.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Fillable Forms$q$, $q$Add text fields, checkboxes, and other form elements to turn a static PDF into something others can fill out.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Page Management$q$, $q$Merge, split, reorder, or delete pages within a PDF document.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Additional Cloud Storage Integrations$q$, $q$Connect Dropbox, OneDrive, and Box in addition to Google Drive for importing and exporting documents.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$DocHub Intelligence (AI Tools)$q$, $q$AI Assistant, Smart Edit, and Enhanced Search features available on paid plans to speed up editing and finding content within documents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Mobile Apps$q$, $q$iOS and Android apps for editing and signing PDFs from a phone or tablet.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Templates & Shared Folders$q$, $q$Save reusable document templates and organize files into shared folders for teams on paid plans.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Bulk Send & In-Person Signing$q$, $q$Send a document to many recipients at once or collect a signature in person on a shared device, available on the Pro tier and above.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Deep, genuinely useful integration with Gmail and Google Drive for editing and signing without downloading files$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free plan available with no expiration, useful for occasional or light users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Low learning curve — most core tasks are accessible without training$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Per-user pricing on Basic and Pro tiers is generally cheaper than dedicated e-signature platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Cross-platform access via web browser, browser extension, and iOS/Android apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free plan is capped at a small number of document actions per month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Lighter on advanced PDF authoring tools (redaction, precise layout editing, heavy OCR correction) compared to full desktop PDF suites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Browser-based performance can lag on very large or complex PDF files$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Team, template, and AI features are locked behind Basic, Pro, or Site License tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Enterprise compliance and support depth are less extensive than platforms built primarily for large-organization document workflow$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Is DocHub free to use?$q$, $q$Yes. DocHub has a free plan that doesn't expire, though it limits users to a small number of completed documents and sign requests per month. Paid Basic and Pro plans remove those caps and add more features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Does DocHub integrate with Google Drive and Gmail?$q$, $q$Yes, this is one of DocHub's core strengths. It's available through the Google Workspace Marketplace and lets users open, edit, and save PDFs directly from Gmail and Google Drive without downloading a local file first.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Who owns DocHub?$q$, $q$DocHub was founded in 2014 and acquired by airSlate, Inc., a Boston-area document workflow and automation company, in July 2022. It continues to operate as part of airSlate's product lineup.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$What's the difference between DocHub's free and paid plans?$q$, $q$The free plan caps core actions like completed edits and sign requests at a small number per month. Paid plans (Basic, Pro, and the Site License enterprise tier) remove those limits and progressively add team features, templates, AI-assisted editing, and admin controls like SSO.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Can DocHub replace a dedicated e-signature platform like DocuSign?$q$, $q$For straightforward signing and sending needs, DocHub's e-signature tools can cover much of the same ground at a lower per-user cost. Organizations with complex approval routing or heavier compliance requirements may still find dedicated e-signature platforms more full-featured.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Signing and sending contracts$q$, $q$Freelancers and small business owners use DocHub to send contracts or agreements for signature and track completion status, without a full e-signature platform subscription.$q$, $q$Freelancers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Classroom form completion$q$, $q$Teachers and students working within Google Classroom use DocHub to fill out, annotate, and submit PDF worksheets and forms directly from Google Drive.$q$, $q$Teachers and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$HR and administrative paperwork$q$, $q$HR and office administrators use DocHub to fill in and route routine paperwork such as intake forms, offer letters, or onboarding documents stored in Google Drive.$q$, $q$HR and administrative staff$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Recurring small-team document workflows$q$, $q$Small teams use shared folders and templates on paid plans to standardize recurring documents, like client agreements or invoices, that need light editing and signature collection each time.$q$, $q$Small business teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 3 completed documents per month","Up to 3 sign requests per month","Basic PDF editing tools (text, draw, highlight)","Mobile apps (iOS and Android)","Up to 3 folders"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Basic$q$, $q$$8/user$q$, $q$monthly (billed annually)$q$, $q$["Unlimited PDF downloads","Unlimited self-signing","Advanced PDF tools (fillable fields, attachments)","Unlimited templates and folders","Up to 5 team members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Pro$q$, $q$$12/user$q$, $q$monthly (billed annually); higher if billed monthly$q$, $q$["Unlimited editing and sign requests","DocHub Intelligence suite (AI Assistant, Smart Edit, Enhanced Search)","Bulk send and in-person signing","Unlimited team members","Document password protection and certification","30-day free trial available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$Site License$q$, $q$Custom$q$, $q$contact sales$q$, $q$["Unlimited users","Volume discounts","Organizations and shared rooms","HIPAA support","Single sign-on (SSO) and priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocHub is a browser-based tool for editing, annotating, filling, and signing PDF documents without installing desktop software. Founded in 2014, it was acquired by document-workflow company airSlate in 2022 and now operates as part of airSlate's broader suite of document automation products, though it still runs as a standalone web app and browser extension.$q$, $q$The product's defining feature is how tightly it plugs into Google Workspace. Users can open a PDF straight from Gmail or Google Drive, mark it up or sign it in a few clicks, and save the result back to the same cloud folder without downloading a local copy. Dropbox, OneDrive, and Box integrations extend the same workflow to other cloud storage providers.$q$, $q$DocHub uses a freemium structure: a permanently free tier with a small monthly allowance of edits and sign requests, and paid Basic, Pro, and Site License (enterprise) tiers that remove those caps and add team, template, and AI-assisted editing features. It is positioned as a lighter, cheaper alternative to full desktop PDF suites and dedicated e-signature platforms rather than a direct feature-for-feature replacement for either.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$who-dochub-is-for$q$, $q$Who DocHub Is For$q$, 2, ARRAY[$q$DocHub suits individuals and small teams whose work already lives in Gmail and Google Drive and who want to handle routine PDF tasks — filling a form, adding a signature, marking up a document — without switching to a separate desktop application.$q$, $q$It's a good fit for freelancers, small business owners, and administrative staff who need a straightforward way to send documents out for signature and track when they come back, at a lower monthly cost than dedicated e-signature platforms.$q$, $q$Teachers and students using Google Classroom, along with small teams that just need light collaboration — comments, shared templates, basic form fields — rather than a full document management or approval-routing system, also tend to find DocHub's scope a good match for their needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need rigorous audit trails, complex multi-department approval routing, or advanced compliance controls beyond what the Site License tier offers will likely find more mature, enterprise-grade options in platforms built specifically around large-scale document workflow and e-signature compliance.$q$, $q$Users who rely on advanced desktop PDF authoring — heavy redaction, precise print production, deep OCR correction, or fine control over the underlying text layout — will find DocHub's browser-first toolset noticeably lighter than a full desktop PDF suite.$q$, $q$Anyone who needs more than a handful of edits or signature requests per month should plan on a paid tier from the start: the free plan's monthly cap on core actions is tight, and per-user monthly fees on Basic and Pro should be weighed against alternatives before committing a whole team to the platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core editing tools cover the basics of working with an existing PDF: adding or editing text, drawing and highlighting, inserting images, and managing pages — merging, splitting, reordering, or deleting them. Fillable form fields can be added to turn a static PDF into a form others can complete.$q$, $q$E-signature functionality lets users request signatures from others, sign documents themselves, and, on paid tiers, send documents in bulk or complete in-person signing on a shared device. Cloud integrations with Google Drive, Gmail, Dropbox, OneDrive, and Box mean documents can be opened, edited, and saved without ever touching a local file.$q$, $q$Paid tiers add team- and admin-oriented features — organizations, shared templates and folders, document password protection and certification — plus an AI layer (DocHub Intelligence) that includes an assistant, smart-edit suggestions, and enhanced document search. The top Site License tier adds unlimited users, single sign-on, and HIPAA support for larger organizations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d074be80-8a70-4e05-b0ba-7f4e75eb95d5', $q$dochub-experience$q$, $q$The DocHub Experience$q$, 2, ARRAY[$q$Day to day, DocHub feels like a simple web app: open a PDF, use a toolbar to annotate or sign it, and use a side panel to manage pages. The learning curve for basic tasks — filling a form, adding a signature, highlighting text — is low, which is a big part of its appeal to non-technical users.$q$, $q$Because everything runs in the browser, performance is tied to document size, complexity, and connection quality. Very large or image-heavy PDFs can take noticeably longer to load and render than they would in a native desktop application, which is worth testing with your own typical files before relying on it for high-volume work.$q$, $q$Overall, the experience trades depth for simplicity: fewer menus and options than a full desktop PDF suite, in exchange for a faster path to common tasks. That makes it a comfortable daily tool for casual and light-business use, while teams with heavier document-production needs may still want a dedicated design or publishing tool alongside it.$q$]::text[], 4);
