INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Page-by-page analytics$q$, $q$See exactly how much time each viewer spent on every page of a shared document, not just whether the link was opened.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Real-time viewer notifications$q$, $q$Get notified the moment someone opens a shared link, including their name or email if verification was required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Access revocation and link control$q$, $q$Turn off access to a shared document at any time, even after it has already been viewed or forwarded.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Swappable file behind a static link$q$, $q$Update the underlying document without changing the link, so previously shared links always point to the latest version.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Email verification, passcodes, and NDA gating$q$, $q$Require a verified email address, a passcode, or NDA acceptance before a recipient can view sensitive material.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Data rooms$q$, $q$Organize multiple related documents into a single secure space for processes like fundraising diligence or deal review.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Custom branded links$q$, $q$Share documents through links and viewers that reflect a company's own branding rather than a generic DocSend domain.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$CRM integrations$q$, $q$Connect with tools like Salesforce so document engagement data can surface alongside deal and contact records.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$E-signature support$q$, $q$Collect signatures on shared documents through integration with Dropbox Sign.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Detailed page-level engagement analytics that generic file-sharing tools don't offer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Ability to revoke access or swap the underlying file without sending a new link$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Well suited to fundraising and sales workflows, including dedicated data rooms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Backed by Dropbox's infrastructure and ongoing security investment since the 2021 acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$No software installation required for recipients to view shared documents$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$No permanent free plan, so casual or occasional users pay for features they may not need$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Per-user seat pricing on team plans can become costly as a team grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Not designed for real-time collaborative editing of documents$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Recipients view files through DocSend's own viewer rather than a familiar native app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Some higher-value features like e-signature and custom branding are limited to higher-priced plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Is DocSend free to use?$q$, $q$DocSend does not offer a permanent free plan. It offers a free trial period so new users can test the product, but continued use requires a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$What is DocSend mainly used for?$q$, $q$DocSend is most commonly used for sharing pitch decks with investors during fundraising, sending sales proposals and pricing documents, distributing board decks, and controlling access to sensitive business documents.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$How does DocSend's analytics feature work?$q$, $q$When a document is shared through a DocSend link, the platform tracks how the recipient interacts with it, including time spent on each page, whether it was reshared, and when it was reopened, and reports this back to the sender on a dashboard.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Is DocSend owned by Dropbox?$q$, $q$Yes. Dropbox acquired DocSend in 2021, and it continues to operate as a distinct product focused on document sharing and analytics within the Dropbox portfolio.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Can people download the files I share through DocSend?$q$, $q$DocSend's viewer is designed to discourage casual downloading by displaying documents in-browser rather than as a direct file download, though this acts as a deterrent rather than absolute copy protection.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Startup fundraising decks$q$, $q$Founders share pitch decks with investors through trackable links, letting them see which slides get the most attention and when an investor revisits the deck.$q$, $q$Startup founders and fundraising teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Sales proposal tracking$q$, $q$Sales reps send proposals and pricing sheets through DocSend to see whether and when a prospect actually opened the document, helping time follow-up outreach.$q$, $q$Account executives and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Investor and board reporting$q$, $q$Investor relations teams distribute board decks and periodic shareholder updates with controlled access and confirmation that recipients received and reviewed them.$q$, $q$Investor relations teams and company boards$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Client deliverables for agencies and consultants$q$, $q$Agencies and consulting firms share finished deliverables, reports, and proposals with clients through branded, access-controlled links instead of email attachments.$q$, $q$Agencies, consultants, and professional services firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Personal$q$, $q$Around $15/month$q$, $q$Billed annually$q$, $q$["Unlimited trackable links","Basic page-by-page analytics","Single user","Email verification on links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Standard$q$, $q$Around $45/user/month$q$, $q$Billed annually$q$, $q$["Team management","Data rooms","More storage","Advanced analytics","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Advanced$q$, $q$Around $150/user/month$q$, $q$Billed annually$q$, $q$["Custom branded links","E-signature via Dropbox Sign","CRM integrations","Advanced security controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$Enterprise / Data Rooms$q$, $q$Custom pricing$q$, $q$Contact sales$q$, $q$["Unlimited data rooms","Single sign-on (SSO)","Dedicated account support","Advanced admin controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocSend is a secure document sharing and analytics platform originally built for founders raising capital and sales teams sending proposals. Founded in 2013 in San Francisco, it was acquired by Dropbox in 2021 and now operates as part of the Dropbox family of products, while continuing to run as its own dedicated service for document distribution and tracking, with its own login and pricing separate from the main Dropbox storage plans.$q$, $q$The core idea is simple: instead of emailing a PDF or PowerPoint file as an attachment, users upload it to DocSend and share a link. Recipients view the document in a browser-based viewer rather than downloading a raw file, and the sender gets a live dashboard showing who opened the link, which pages they spent the most time on, whether they forwarded it, and when they came back for a second look.$q$, $q$That page-level visibility is what differentiates DocSend from generic file-sharing tools like Dropbox's own folder sharing or Google Drive links. It turns a static document into a source of feedback: a startup can see which slide of its pitch deck investors lingered on, and a sales rep can see whether a prospect actually opened the proposal before a follow-up call. This distribution-plus-feedback loop is the reason DocSend has stayed relevant even as general-purpose file storage has become a commodity.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$who-docsend-is-for$q$, $q$Who DocSend Is For$q$, 2, ARRAY[$q$Founders and startup teams raising a funding round are among DocSend's most visible users. Sharing a pitch deck through DocSend lets them see which investors have opened it, how far they got, and how long they spent on the financials or team slide, which helps prioritize follow-up conversations during a fundraising process.$q$, $q$Sales and business development teams are the other major audience. Account executives use DocSend to send proposals, pricing sheets, and case studies, then use the open and engagement data to gauge real interest and time their outreach, rather than guessing whether a prospect actually read what was sent.$q$, $q$It's also a good fit for investor relations teams distributing board decks and shareholder updates, agencies and consultants sending client deliverables, and any team that needs to control who can view a sensitive document, revoke access after the fact, or require an NDA or email verification before someone can open a file. Teams that operate in regulated or confidentiality-sensitive industries, such as legal or financial services, often value the added layer of control over a plain file attachment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$People who just want a quick, free way to share a file with a friend or colleague don't need DocSend. There is no permanent free tier, and paying for engagement analytics on documents you don't need to track is unnecessary overhead when a plain Dropbox or Google Drive link already does the job.$q$, $q$Teams that need real-time collaborative editing, like co-writing a document or spreadsheet together, are also not the target audience. DocSend is built around one-way distribution of finished documents with tracking, not multi-user editing, comments, or version branching the way Google Docs or Notion handle collaboration.$q$, $q$Very small budgets or solo users with only occasional sharing needs may find the per-seat pricing on team plans hard to justify, especially if the extra features like data rooms, custom branding, or e-signature aren't actually needed. In those cases, a general-purpose cloud storage tool is more cost-effective, at least until the volume of outbound documents and the need for engagement data grows.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of DocSend is its analytics engine: every shared link reports page-by-page time spent, total viewing duration, geographic location of viewers, and whether the document was reshared to someone new. This data updates in real time, so senders can get a notification the moment someone opens a document.$q$, $q$Access controls round out the security side of the product. Links can require an email address, a passcode, or NDA acceptance before the content loads, and access can be revoked at any time, even after a link has been sent out and viewed. Because the underlying file is swappable, senders can update a document without needing to send a new link.$q$, $q$For larger workflows, DocSend offers data rooms that bundle multiple documents together for processes like fundraising due diligence, plus custom-branded links, integrations with tools like Salesforce, and e-signature capability through Dropbox Sign. These sit on top of the base sharing and analytics functionality rather than replacing it, so a team can start with simple trackable links and grow into data rooms and e-signature as its needs get more complex.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', $q$docsend-experience$q$, $q$The DocSend Experience$q$, 2, ARRAY[$q$Getting started with DocSend is straightforward: create an account, upload a PDF, slide deck, or Word document, and a shareable link is generated immediately. The upload-to-link flow is quick enough that it fits naturally into an existing sales or fundraising workflow without much friction.$q$, $q$The sender-facing dashboard is where most of the day-to-day value shows up, listing every link that's been shared along with a visual breakdown of viewer engagement per page. For frequent users, like a founder mid-fundraise or a sales rep working several active deals, checking this dashboard becomes a regular part of deciding who to follow up with next.$q$, $q$On the recipient side, the experience is deliberately lightweight: documents open in a browser viewer with no account or software installation required, which keeps the barrier to viewing low even though the sender is collecting engagement data behind the scenes. Since the 2021 Dropbox acquisition, DocSend has also become more closely tied into the broader Dropbox ecosystem for account management and sign-in, while its core sharing and analytics workflow has stayed largely consistent for existing users.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edbc5167-46cb-4d31-8eb3-4c9d8b6f911a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
