INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Magic ETL$q$, $q$A visual, drag-and-drop data transformation tool for cleaning, joining, and reshaping data from multiple sources without writing SQL.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Extensive connector library$q$, $q$Prebuilt connectors to a wide range of cloud apps, databases, and files, letting teams centralize data from many systems into one platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo.AI$q$, $q$Generative AI features layered across the platform, including natural-language data queries, AI-assisted chart and formula generation, and conversational data exploration.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$App Studio$q$, $q$A framework for building custom, purpose-built data apps on top of connected data sets, beyond standard dashboards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo Everywhere$q$, $q$Embedding capability for publishing live dashboards and analytics inside external products, customer portals, or client-facing sites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Workflows$q$, $q$Automation tooling for building data-driven business processes and approvals that trigger off changes in connected data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Real-time dashboards and alerts$q$, $q$Interactive, drag-and-drop dashboards with threshold-based alerting so teams are notified when metrics move outside expected ranges.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Mobile apps$q$, $q$Native iOS and Android apps for viewing dashboards, receiving alerts, and exploring data away from a desktop.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Governance and federation$q$, $q$Role-based access controls, data cataloging, and federation features for managing permissions and data quality at scale.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo Workbench$q$, $q$A desktop utility for syncing on-premises databases, files, and legacy systems into the cloud platform.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Combines data integration, transformation, visualization, apps, and embedding in one platform rather than several separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Very large library of prebuilt connectors covering common cloud apps and databases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Low-code tools like Magic ETL and App Studio let non-engineers build data pipelines and apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Strong embedded analytics option (Domo Everywhere) for companies delivering dashboards to their own customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Native mobile apps make it easy to monitor metrics and alerts outside the browser$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Pricing is not published and requires a sales conversation, making budgeting harder upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Consumption-based elements can make total cost less predictable as data volume and users grow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Breadth of features (ETL, apps, automation, embedding, AI) creates a steeper learning curve than single-purpose BI tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Smaller community and third-party learning resources compared to more widely adopted BI tools like Power BI or Tableau$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Best value depends on broad, organization-wide adoption rather than a single team's use, which can slow time-to-value$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Is Domo free to use?$q$, $q$Domo does not publish a free-forever tier for general use; pricing is quote-based and arranged through its sales team, though prospective customers can typically request a guided demo before committing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$How much does Domo cost?$q$, $q$Domo does not publish standard pricing. Cost depends on factors like number of users, data volume, and which modules (such as Workflows or embedding) are included, and is quoted directly by Domo's sales team.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Is Domo a good fit for small businesses?$q$, $q$Domo is generally built for mid-market and enterprise use cases with multiple data sources and teams. Small businesses with simple, single-source reporting needs and tight budgets often find lighter, self-serve BI tools a better match.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$What is Domo.AI?$q$, $q$Domo.AI is the branding Domo uses for its generative AI capabilities layered across the platform, including natural-language data queries, AI-assisted formula and chart generation, and conversational data exploration.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Does Domo have a mobile app?$q$, $q$Yes. Domo offers native mobile apps for iOS and Android that let users view dashboards, drill into data, and receive alerts outside of the desktop browser experience.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Executive and operational dashboards$q$, $q$Consolidating data from finance, sales, and operations systems into unified dashboards so leadership can monitor company performance in near real time.$q$, $q$Executives and operations leaders at mid-market and enterprise companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Embedded customer-facing analytics$q$, $q$Using Domo Everywhere to embed live dashboards inside a company's own product or client portal instead of building a custom reporting layer in-house.$q$, $q$SaaS vendors and agencies delivering analytics to their own clients$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Marketing performance reporting$q$, $q$Blending data from multiple ad platforms, CRM systems, and web analytics tools into unified marketing dashboards using Magic ETL and prebuilt connectors.$q$, $q$Marketing teams and agencies managing multi-channel campaigns$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Cross-department data governance$q$, $q$Centralizing data access, permissions, and quality controls for large organizations running many dashboards and apps across multiple business units.$q$, $q$IT and data governance teams at large enterprises$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Starter$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, $q$["Core dashboards and visualizations","Access to a subset of data connectors","Basic collaboration and alerting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Professional$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, $q$["Expanded connector access and higher data limits","Magic ETL data transformation","App Studio for building custom data apps","Mobile app access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, $q$["Domo Everywhere embedded analytics","Advanced governance, federation, and role-based access controls","Workflows automation","Dedicated support and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Domo is a cloud-native business intelligence and data analytics platform founded in 2010 and headquartered in American Fork, Utah. The company is publicly traded on the Nasdaq under the ticker DOMO. Rather than positioning itself as a single-purpose dashboarding tool, Domo markets itself as an end-to-end data platform that pulls together data integration, storage, visualization, app building, and workflow automation in one connected environment.$q$, $q$Under the hood, Domo runs on a cloud architecture it calls Adrenaline, paired with a connector library that claims to link to well over a thousand data sources, from cloud SaaS apps and databases to spreadsheets and on-premises systems via a sync tool called Workbench. Data can be blended and reshaped using Magic ETL, a drag-and-drop transformation builder, before it lands in dashboards, alerts, or custom-built apps created through App Studio.$q$, $q$More recently, Domo has layered generative AI features across the platform under the Domo.AI umbrella, including natural-language querying, AI-assisted formula and chart creation, and conversational data exploration. The overall pitch is consolidation: instead of stitching together a separate ETL tool, a data warehouse, a BI tool, and an embedding solution, organizations run all of it inside one vendor's stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$who-domo-is-for$q$, $q$Who Domo Is For$q$, 2, ARRAY[$q$Domo tends to fit mid-market and larger enterprises whose data is scattered across many cloud applications and departments, and who want a single system to unify reporting rather than maintaining separate tools per team. Companies in retail, marketing, financial services, and healthcare frequently show up among its user base because those industries typically combine many data sources with a need for frequent, operational (not just monthly) reporting.$q$, $q$It's also a strong candidate for organizations that want to embed analytics into a product or customer-facing portal rather than keeping dashboards internal only. The Domo Everywhere embedding capability is aimed squarely at software vendors, agencies, and service providers that want to hand clients live dashboards without building a reporting layer from scratch.$q$, $q$On the user side, Domo suits business analysts and operations teams who want to prepare and visualize data without writing much code, while still giving IT and data teams governance controls, row-level security, and federation options as usage scales across many teams and data sets.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, solo analysts, or teams with a tight, predictable budget may find Domo a poor fit. Pricing is not published and is negotiated through sales, and the platform's consumption-based elements (data rows, user seats) can make costs harder to forecast than a flat-rate self-serve tool.$q$, $q$Teams already standardized on Power BI, Tableau, Looker, or an open-source BI stack, with staff skilled in those tools, generally have little reason to migrate; switching costs and retraining time can outweigh the benefits Domo offers over a familiar incumbent.$q$, $q$Organizations that only need occasional, simple reporting from one or two data sources — without a need for embedding, automation, or cross-department governance — are usually better served by a lighter, self-signup analytics tool rather than a full platform built for large-scale data consolidation.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the data layer, Domo offers a large prebuilt connector catalog, Workbench for syncing on-premises and desktop data sources, and Magic ETL for visual, low-code data transformation and blending across sources without hand-written SQL pipelines.$q$, $q$On the analytics and app layer, Domo provides drag-and-drop dashboards, alerting, and App Studio for assembling purpose-built data apps, plus native mobile apps for iOS and Android so users can check metrics and receive alerts away from a desktop.$q$, $q$Governance and extensibility round out the platform: role-based access, data governance and cataloging features, Workflows for automating data-driven processes, Domo Everywhere for embedding dashboards into external products, and Domo.AI features layered across search, chat, and formula generation.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$domo-experience$q$, $q$The Domo Experience$q$, 2, ARRAY[$q$Getting started with Domo typically involves a sales-led demo and a scoping conversation rather than a self-serve signup, since implementations often require planning around connectors, data governance, and how many teams will use the platform from day one.$q$, $q$Day to day, the experience is a browser-based workspace centered on drag-and-drop dashboard building, with AI chat and natural-language query features layered in to help less technical users pull answers without writing formulas, alongside mobile apps for monitoring metrics on the go.$q$, $q$Overall, Domo rewards organizations willing to invest time in setup and governance with a genuinely unified data stack, but it is less turnkey than lightweight BI tools; the value shows up most clearly when adoption spreads across many teams rather than staying confined to a single dashboard or department.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
