INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$AI Website Generator$q$, $q$Generates a multi-page starter website with layout and copy from a short text prompt describing the business or niche, which users then refine in the visual editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Drag-and-Drop Visual Editor$q$, $q$A block- and element-based canvas editor for arranging page layouts and styling without writing code, with automatic responsive behavior across devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Built-in Blog and CMS$q$, $q$A content management system with custom fields and collections plus a blogging engine supporting multi-author publishing, post scheduling, and one-click import from WordPress, Ghost, Medium, and Substack.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Native SEO Controls$q$, $q$Page-level meta titles and descriptions, focus keyword settings, custom schema markup, canonical URLs, hreflang tags, sitemap controls, and robots.txt editing without needing a separate plugin.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$White-Label Client Sites$q$, $q$Business and Agency plans support custom-branded dashboards and client billing, letting agencies and freelancers resell websites under their own studio name.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Third-Party Integrations$q$, $q$Over 40 integrations including Zapier, Mailchimp, and a native Airtable connector for pulling live data into pages, plus payment options through Stripe, PayPal, and Gumroad.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Code Export$q$, $q$Exports finished sites as static HTML, CSS, and JavaScript, giving users the option to host the output outside of Dorik if needed.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Team Collaboration and Roles$q$, $q$Custom collaborator roles and permissions for teams and agencies, with the number of available collaborators varying by plan.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Forms and Password-Protected Pages$q$, $q$Built-in contact and subscription forms plus the ability to restrict access to specific pages with a password, useful for client previews or gated content.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Free plan includes unlimited pages, storage, bandwidth, and a real custom domain with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$AI website generator produces a usable starting layout and copy in under a minute$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Native SEO tools (schema, canonical URLs, sitemap, robots.txt) reduce reliance on third-party plugins$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Long-term paid plans are notably cheaper than comparable builders like Webflow or Wix$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$White-label and client billing tools make it a viable option for agencies reselling websites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Editor offers less granular styling and interaction control than code-adjacent builders like Webflow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$No true e-commerce engine, only payment links via Stripe, PayPal, or Gumroad rather than a full cart and inventory system$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$No native iOS or Android app; the product is web-based only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Smaller template and integration ecosystem than more established competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Higher collaborator counts and full white-label features require the pricier Business or custom Agency plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Is Dorik actually free to use?$q$, $q$Yes, Dorik has a free plan that includes unlimited websites, pages, and blog posts, unlimited storage and bandwidth, a custom domain, and a free SSL certificate, with no credit card required to sign up.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Can I sell products with Dorik?$q$, $q$Dorik supports basic selling through payment buttons and links connected to Stripe, PayPal, or Gumroad, but it does not include a full e-commerce system with product catalogs, inventory management, or cart-based checkout.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Can I export a website built in Dorik?$q$, $q$Yes, Dorik allows exporting a finished site as static HTML, CSS, and JavaScript, which gives users a way to host the exported files elsewhere if they choose to leave the platform.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Does Dorik offer a trial of its paid plans?$q$, $q$Dorik offers a short free trial period with full access to paid-plan features before committing, in addition to its permanently free base plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$How does Dorik compare to Webflow or Wix?$q$, $q$Dorik is generally positioned as a more affordable, simpler alternative to Webflow and Wix, trading some of their deeper custom-design and interaction controls for a gentler learning curve and lower-cost long-term pricing.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Solo founders and freelancers building a personal or business site$q$, $q$Quickly launching a portfolio, personal brand, or small business site using templates or the AI generator without hiring a developer.$q$, $q$Freelancers, consultants, and independent professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Small business and local service websites$q$, $q$Setting up a marketing site with contact forms, service pages, and a custom domain on a limited budget.$q$, $q$Small business owners and local service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Blogging and content publishing$q$, $q$Running a blog with the built-in CMS, importing existing posts from WordPress, Ghost, Medium, or Substack, and managing SEO metadata natively.$q$, $q$Bloggers, writers, and content creators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Agency client website delivery$q$, $q$Building and managing multiple client websites under a white-label dashboard with custom branding and client billing.$q$, $q$Web design agencies and freelance designers managing multiple clients$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Unlimited websites, pages, and blog posts","Custom domain support","Unlimited storage, bandwidth, and pageviews","Free SSL certificate","Basic AI website generation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Personal$q$, $q$From $10.38/mo (billed every 2 years); $29/mo billed monthly$q$, $q$Monthly or multi-year$q$, $q$["1 custom domain","Up to 25 pages","Up to 200 blog posts","Unlimited storage","Native SEO tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Business$q$, $q$From $20.75/mo (billed every 2 years); $59/mo billed monthly$q$, $q$Monthly or multi-year$q$, $q$["Up to 3 custom domains","Unlimited pages and blog posts","Up to 10 collaborators","White-label dashboard","Client billing tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Agency$q$, $q$Custom pricing (contact sales); listed from $99/mo billed monthly$q$, $q$Monthly, annual, or custom$q$, $q$["Unlimited domains","Unlimited pages and blog posts","Unlimited collaborators","Full white-label branding","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dorik is a no-code website builder that lets individuals and small teams design and publish websites without writing HTML, CSS, or JavaScript. The core of the product is a visual, drag-and-drop editor where users place pre-built blocks and elements onto a canvas and adjust layout, spacing, and styling directly, with the editor automatically handling responsive behavior across desktop, tablet, and mobile breakpoints.$q$, $q$The company was started in Sylhet, Bangladesh, as a side project in 2019 by co-founders who had previously built websites and templates since 2012, and it launched publicly in mid-2020. Dorik built its early reputation on affordability, offering a free plan with unlimited pages and a real custom domain, which positioned it as a budget-friendly alternative to more expensive builders like Webflow, Wix, and Squarespace.$q$, $q$Beyond the visual editor, Dorik bundles a built-in CMS and blogging engine, native SEO controls, dozens of third-party integrations, and an AI website generator that produces a starter multi-page site from a short text prompt. The pitch is an all-in-one platform that combines hosting, design, content management, and basic marketing tools in one dashboard rather than requiring a stack of plugins.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$who-dorik-is-for$q$, $q$Who Dorik Is For$q$, 2, ARRAY[$q$Dorik suits freelancers, consultants, and small business owners who need a professional-looking website quickly and don't want to hire a developer or learn to code. The low cost of entry, including a fully functional free tier and inexpensive long-term paid plans, makes it attractive to solo founders and side-project builders working with tight budgets.$q$, $q$Content creators and bloggers are another good fit, since Dorik includes a blog CMS with one-click import from WordPress, Ghost, Medium, and Substack, along with meta tag, canonical URL, and schema markup controls that reduce the need for a separate SEO plugin stack.$q$, $q$Agencies and freelance web designers who build sites for clients can use the Business and Agency plans for white-label dashboards, client billing, and custom-branded admin panels, letting them resell Dorik under their own studio name rather than exposing the underlying platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers and teams that need pixel-perfect custom interactivity, complex web applications, or deep custom logic will likely find Dorik too constrained. It is intentionally scoped as a no-code marketing and content site builder, and it doesn't offer the CSS-grid-level styling controls or custom interaction/animation panel that a tool like Webflow provides.$q$, $q$Businesses that need a full online store are not well served here either. Dorik supports payment buttons and links through Stripe, PayPal, and Gumroad, but it lacks a true e-commerce engine with product catalogs, inventory tracking, cart logic, and shipping or tax rule automation, so multi-product retailers should look at a dedicated e-commerce platform instead.$q$, $q$Teams that need native mobile apps, offline editing, or a large number of low-cost collaborator seats should also weigh alternatives, since Dorik is web-based only with no iOS or Android app, and higher collaborator counts are gated behind the pricier Business and Agency tiers.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The visual editor is built around a library of pre-designed blocks and individual elements that can be dragged onto a page and restyled, giving users a middle ground between rigid templates and a blank-canvas builder. Hundreds of starter templates across categories like portfolio, business, blog, and one-page sites give new users a working layout to customize rather than starting from scratch.$q$, $q$Dorik's AI website generator takes a short prompt describing a business or niche and produces a multi-page starter site with matching copy and layout, which users then edit in the visual builder. This sits alongside a built-in CMS with custom fields and collections, a blogging engine with multi-author support and post scheduling, and native SEO tools covering meta titles, focus keywords, custom schema, canonical URLs, hreflang tags, sitemap controls, and robots.txt editing.$q$, $q$Rounding out the platform are more than 40 integrations (including Zapier, Mailchimp, and a native Airtable connector for live data), form building with password-protected pages, free SSL on every plan, HTML/CSS/JS code export for users who want to move hosting elsewhere, and collaboration features with custom roles and permissions for agencies managing client work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$dorik-experience$q$, $q$The Dorik Experience$q$, 2, ARRAY[$q$New users typically start from either a template or the AI generator, then land in the drag-and-drop editor to adjust sections, swap images and copy, and fine-tune spacing. The editor is generally described as approachable for non-technical users, with a shorter learning curve than more powerful but complex builders, though power users may hit ceiling moments where they want more granular control than the block system allows.$q$, $q$Support is handled through documentation, tutorials, and live chat rather than a large self-serve community or marketplace, so users troubleshooting an edge case will lean more on direct support than on third-party plugins or forum answers, which is a tradeoff of Dorik's smaller ecosystem compared to long-established competitors.$q$, $q$Overall the experience is oriented around speed to a finished, reasonably polished website rather than deep customization, which matches Dorik's positioning as an affordable, all-in-one option for small businesses, creators, and agencies producing straightforward marketing and content sites.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
