INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Automatic transcription$q$, $q$Uploads of interview and call recordings are automatically transcribed to text, removing manual note-taking during sessions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Tagging and thematic analysis$q$, $q$Researchers or AI apply tags to specific moments in transcripts so recurring themes across many sessions can be surfaced and compared.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Insights repository$q$, $q$Past projects, transcripts, and tags remain searchable long-term, so new questions can often be answered from existing research instead of starting over.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$AI chat and summaries$q$, $q$A chat-style interface lets users ask natural-language questions across a project's data, with AI-generated summaries of individual sessions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Channels for continuous feedback$q$, $q$Channels automatically ingest and classify ongoing feedback sources like support tickets or sales call notes into recurring topics and emerging issues.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Dashboards$q$, $q$Visual dashboards chart feedback trends and themes alongside business metrics for a higher-level view of customer signals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Docs for shareable reports$q$, $q$Findings can be compiled into shareable written docs so insights reach stakeholders outside the research team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Highlight reels$q$, $q$Clips and quotes tagged as evidence can be assembled into a highlight reel to support a specific finding or recommendation.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Integrations and API$q$, $q$Dovetail connects with tools such as Zoom, Slack, Zendesk, Salesforce, and calendar apps, plus an API for custom data connections.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Projects, permissions, and workspaces$q$, $q$Content is organized into projects and workspaces with permission controls governing who can view, edit, or contribute.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$AI-assisted tagging and summarization reduce the manual effort of analyzing large volumes of interviews and feedback$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Acts as a central, searchable repository that keeps research findings from becoming siloed in individual documents$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Broad integrations with common product, support, and sales tools help consolidate feedback from multiple sources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$A genuine free plan exists for individuals or very small teams getting started$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Mature, widely used product with features purpose-built for UX research and research operations workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Pricing above the free plan is not fully published, requiring a sales conversation to get exact costs for most teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Does not include participant recruitment, screening, or incentive payment tools, so extra tools are still needed to source participants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$AI-generated summaries and tags can miss nuance and should be reviewed rather than trusted outright$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Tagging conventions and repository structure take real setup effort, which can be a lot for teams with only occasional research needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$No dedicated native mobile apps; the product is used through a web browser$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$What is Dovetail used for?$q$, $q$Dovetail is used to transcribe, tag, and analyze qualitative customer data such as interviews, usability tests, surveys, support tickets, and sales calls, and to store the resulting insights in a searchable repository that multiple teams can reuse.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Is Dovetail free to use?$q$, $q$Dovetail offers a free plan with limited projects, channels, and AI features. Paid plans unlock unlimited projects, higher transcription and storage limits, and advanced AI and security features, with Enterprise pricing available by contacting sales.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Does Dovetail transcribe interviews automatically?$q$, $q$Yes, Dovetail automatically transcribes uploaded audio and video recordings, which can then be tagged and analyzed alongside other qualitative data in the same project.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Can Dovetail integrate with other tools?$q$, $q$Yes, Dovetail integrates with tools such as Zoom, Slack, Zendesk, Salesforce, and calendar apps, and it offers an API for connecting additional data sources or building custom workflows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Who founded Dovetail and when?$q$, $q$Dovetail was founded in 2017 in Sydney, Australia, by former Atlassian colleagues, and has since grown into a broader customer intelligence platform used by research, product, and customer-facing teams.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Centralizing user research findings$q$, $q$Research teams upload interviews, usability tests, and diary study data into Dovetail, tagging key moments so findings remain searchable across every past study rather than trapped in individual documents.$q$, $q$UX researchers and research operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Grounding roadmap decisions in customer evidence$q$, $q$Product managers and designers search Dovetail's repository for existing interviews and highlight reels to support prioritization decisions with direct customer quotes instead of relying only on internal assumptions.$q$, $q$Product managers and product designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Making sense of support and sales feedback at scale$q$, $q$Customer experience and sales teams route tickets and call transcripts into Dovetail channels, where AI classification surfaces recurring issues and shifting sentiment across large volumes of feedback.$q$, $q$Customer experience and sales teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Running continuous discovery cycles$q$, $q$Cross-functional teams practicing continuous discovery use Dovetail to log ongoing customer conversations and quickly retrieve prior evidence when new product questions come up.$q$, $q$Agile product and design teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Free$q$, $q$$0$q$, $q$Free, no card required$q$, $q$["One project","One feedback channel","Basic AI summaries and AI chat","Search and contacts","Calendar and integration syncing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Professional$q$, $q$Not published by Dovetail; third-party estimates range from roughly $29 to $49 per editor/month billed annually$q$, $q$Reported to be billed annually per editor$q$, $q$["Unlimited projects","Fuller AI analysis features","Higher transcription and storage limits","Standard integrations","Team permissions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom annual contract$q$, $q$["Unlimited channels, projects, and docs","Unlimited free viewers","Single sign-on and advanced security/compliance controls","Dedicated customer success support","Advanced AI features including semantic search"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dovetail is a customer intelligence and user research platform founded in 2017 in Sydney, Australia, by former Atlassian colleagues. It began as a simple tool for organizing diary studies and interview notes and has grown into a broader system for capturing, analyzing, and sharing customer feedback across an organization, positioning itself less as a single research tool and more as a shared repository that design, product, sales, and support teams can all draw on for evidence.$q$, $q$At its core, Dovetail lets teams upload interview recordings, survey responses, support tickets, and other qualitative data, then transcribes and tags that material so patterns become visible across many conversations rather than one at a time. AI features assist with summarizing individual sessions, suggesting relevant tags, and answering natural-language questions about the underlying data through a chat-style interface layered on top of a project's transcripts and notes.$q$, $q$Beyond individual studies, Dovetail functions as a long-term insights repository: past research stays searchable so new questions can be answered by re-tagging existing data instead of always starting new work from scratch. It integrates with common tools such as Zoom, Slack, Zendesk, and Salesforce, positioning it as connective tissue between research, product, and customer-facing teams rather than a standalone note-taking or transcription app.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$who-dovetail-is-for$q$, $q$Who Dovetail Is For$q$, 2, ARRAY[$q$Dovetail is aimed primarily at dedicated UX researchers and research operations teams who conduct interviews, usability tests, and diary studies on a regular basis and need a consistent way to store, tag, and retrieve findings instead of scattering recordings and notes across shared drives, spreadsheets, and personal folders. Research-heavy organizations with several researchers working across parallel projects tend to see the most value, since a shared tagging vocabulary and repository become more useful as more people contribute to and search the same body of evidence.$q$, $q$Product managers and designers who practice continuous discovery also rely on it, often as consumers of a shared repository rather than researchers themselves, searching past interviews and highlight reels to ground roadmap decisions in direct customer evidence rather than relying solely on internal opinions or one-off anecdotes from a single stakeholder. This makes Dovetail useful even for people who never conduct an interview personally but need quick, trustworthy answers about what customers have actually said.$q$, $q$Customer experience, support, and sales teams increasingly use Dovetail's channel and AI analysis features to make sense of support tickets, call transcripts, and survey responses at scale, which makes it a reasonable fit for mid-size to large organizations juggling recurring streams of qualitative feedback across several departments at once. Organizations that already have multiple disconnected feedback sources and want one place to reconcile them are often the best-suited candidates.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small teams or solo founders with occasional, lightweight research needs may find Dovetail more than they require; a shared spreadsheet or a simple notes tool can cover a handful of interviews without the setup, tagging conventions, and ongoing repository maintenance that Dovetail expects before its value really starts to compound. Anyone running only one or two studies a year is unlikely to recoup that setup effort.$q$, $q$Teams that need built-in participant recruitment, screening, or incentive payments should note that Dovetail does not include those capabilities; it assumes interviews and surveys are already being sourced and run elsewhere, so organizations without a separate recruitment workflow will still need to pair it with other specialized tools to actually find and schedule participants.$q$, $q$Budget-conscious teams should also be cautious: pricing above the free plan is not fully published on the website, and features like single sign-on or advanced compliance controls sit behind custom Enterprise contracts, which can make Dovetail a harder fit for organizations that specifically want transparent, self-serve pricing without a sales conversation. Teams that have compared several research tools on price alone may find the quoting process slower than they would like.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Dovetail's foundation is transcription and tagging: audio and video interviews are transcribed automatically, then researchers or AI apply tags to specific moments so that similar comments across many sessions can be pulled together into themes, rather than requiring someone to re-read full transcripts every time a new question comes up. Highlight reels then let a researcher assemble the clearest supporting clips into a single shareable view.$q$, $q$AI now runs through most of the workflow, including auto-generated session summaries, suggested tags, a chat interface for asking questions across a project's data, and "channels" that continuously classify incoming feedback such as support tickets or sales call notes into recurring topics, emerging issues, and shifting sentiment over time. "Agents" extend this further by turning recognized customer signals into automated follow-up actions.$q$, $q$For sharing results, Dovetail offers dashboards that chart feedback trends against business metrics, plus "docs" for turning raw findings into shareable written reports for stakeholders. Projects, permissions, and workspaces organize who can see what, while an API and integrations with tools like Slack, Zendesk, Salesforce, and calendar apps connect Dovetail to the rest of a team's existing stack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', $q$dovetail-experience$q$, $q$The Dovetail Experience$q$, 2, ARRAY[$q$New users typically start by importing existing interview recordings or connecting a feedback channel, and the initial experience is fairly straightforward: upload a file, let automatic transcription run, and begin tagging moments of interest. The learning curve increases once teams try to standardize tagging conventions and project structure across many contributors and departments.$q$, $q$The interface leans toward research and product teams already familiar with qualitative analysis concepts like coding and thematic grouping, so newcomers without a research background may need a short ramp-up period before they use tags, highlight reels, and insights consistently rather than treating Dovetail as just another plain document store.$q$, $q$AI-generated summaries and answers speed up analysis considerably but are best treated as a starting point rather than a final word, since automated tagging and summarization can still miss nuance that an experienced human researcher would catch; teams that build in a manual review step tend to get the most reliable, trustworthy results overall.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c7ffe5d-03a8-4aa8-aa1e-04f31e023da0', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$iPad and iPhone native EHR app$q$, $q$Charting, scheduling, and e-prescribing are available through a native iOS app in addition to the web browser, letting clinicians document visits at the point of care.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Customizable clinical templates$q$, $q$Specialty-specific charting templates can be configured per provider, with dictation and speech-to-text support for faster note-taking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$E-prescribing with EPCS$q$, $q$Built-in e-prescribing supports electronic prescribing of controlled substances, so clinicians can send both standard and controlled-substance prescriptions from within the chart.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Practice management and scheduling$q$, $q$Appointment scheduling, patient check-in, and calendar management are integrated with the clinical record rather than run as a separate system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Medical billing and revenue cycle management$q$, $q$Claim scrubbing, electronic claim submission, and denial follow-up are built in, with optional full-service RCM handled by DrChrono's own billing team for practices that want billing outsourced.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Insurance eligibility verification$q$, $q$Patient insurance eligibility can be checked from within the scheduling and billing workflow to reduce claim rejections before a visit.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$OnPatient patient portal$q$, $q$A branded patient portal supports online scheduling, secure messaging, digital intake forms, and online bill payment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Telehealth video visits$q$, $q$Integrated video visit tools let providers conduct telehealth appointments and document them within the same chart as in-person visits.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Open API and app marketplace$q$, $q$DrChrono publishes an open API and maintains a marketplace of third-party integrations, allowing practices to connect labs, imaging systems, and other specialty tools.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Reporting and analytics$q$, $q$Practice and billing dashboards give administrators visibility into scheduling, claims, and collections activity across providers.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$iPad-native charting app that feels closer to a tablet-first product than most browser-based EHR competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Combines clinical charting, practice management, and medical billing in one platform, reducing the number of vendors a practice must manage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Tiered plans let practices choose EHR-only, EHR-plus-billing, or a fully outsourced revenue cycle management option$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$E-prescribing includes controlled substances (EPCS), not just standard medications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Open API and app marketplace support integrations with labs, imaging, and other specialty software$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Pricing is not published and requires a sales conversation, making upfront cost comparison harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Add-on usage fees (such as texting, faxing, or automated calls) and RCM fees based on collections can make total cost less predictable$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Some user reviews describe slower or inconsistent customer support response times$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Setting up specialty templates, fee schedules, and payer connections can involve a real learning curve during onboarding$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Built around U.S. billing, coding, and insurance workflows, so it is not well suited to practices operating outside the United States$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Is DrChrono free to use?$q$, $q$DrChrono is not a free product overall. It offers a no-cost base plan with limited scheduling and charting functionality, but the full EHR, e-prescribing, and billing features require a paid, custom-quoted plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$How much does DrChrono cost?$q$, $q$DrChrono does not publish fixed pricing on its website. Costs are quoted per provider per month based on which tier (EHR only, EHR plus billing, or full-service revenue cycle management) a practice selects, so practices need to contact DrChrono sales for an exact quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Does DrChrono include medical billing?$q$, $q$Yes. DrChrono offers built-in medical billing tools such as claim scrubbing and submission on its mid-tier plans, and a full-service revenue cycle management option where DrChrono's own billing team manages claims and collections.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Is DrChrono HIPAA compliant?$q$, $q$DrChrono is designed and marketed as a HIPAA-compliant EHR platform for U.S. medical practices, with the security and privacy controls expected of a system that stores protected health information.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Does DrChrono work outside the United States?$q$, $q$DrChrono is built primarily around U.S. medical billing, coding, and insurance eligibility workflows, so it is generally not a strong fit for practices operating under non-U.S. healthcare and insurance systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Solo and small independent practices$q$, $q$A single physician or small group can run scheduling, clinical charting, e-prescribing, and billing from one connected system instead of stitching together separate tools.$q$, $q$Solo physicians and small independent practices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Mobile and multi-site providers$q$, $q$Clinicians who see patients across a clinic, hospital rounds, or house calls can chart, e-prescribe, and check schedules from an iPad or iPhone rather than being tied to a desktop.$q$, $q$Physicians who work across multiple care settings$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Practices outsourcing revenue cycle management$q$, $q$Practices that would rather not staff an in-house billing team can move to a plan tier where DrChrono's own billing team manages claim submission, follow-up, and collections.$q$, $q$Practices seeking outsourced medical billing$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Specialty groups needing tailored charting$q$, $q$Groups in specialties like urgent care, pediatrics, or behavioral health can configure specialty-specific templates so charting matches how their clinicians actually document visits.$q$, $q$Specialty medical groups$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Essentials$q$, $q$Custom pricing (contact sales)$q$, $q$Per provider, monthly$q$, $q$["Core EHR and clinical charting","Practice management and scheduling","Mobile iPad and iPhone app","Patient portal access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Advanced$q$, $q$Custom pricing (contact sales)$q$, $q$Per provider, monthly$q$, $q$["Everything in Essentials","E-prescribing, including controlled substances (EPCS)","Insurance eligibility verification","Integrated medical billing and claim submission"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$Elite$q$, $q$Custom pricing (contact sales)$q$, $q$Per provider, monthly$q$, $q$["Everything in Advanced","Full-service revenue cycle management handled by DrChrono's billing team","Advanced reporting and analytics","Dedicated account support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DrChrono is a cloud-based electronic health record (EHR) and practice management platform built for independent medical practices, urgent care clinics, and small-to-midsize specialty groups across the United States. Founded in 2009 by Daniel Kivatinos and Michael Nusimow, the company built its early reputation on an iPad-native charting app at a time when most EHR vendors were still desktop-only, and that mobile-first design remains a core part of its identity today. It is best understood as a combined clinical-and-billing system rather than a pure documentation tool.$q$, $q$The platform combines clinical documentation, scheduling, e-prescribing, and medical billing and revenue cycle management (RCM) in a single system, along with an open API and app marketplace that lets practices connect DrChrono to labs, imaging providers, and other third-party healthcare tools. In November 2021, DrChrono was acquired by EverCommerce and now operates within the company's EverHealth group of healthcare software brands, though it continues to be marketed, sold, and supported as its own distinct product with its own pricing and account teams.$q$, $q$DrChrono is aimed squarely at U.S. ambulatory practices that need to manage clinical charting and insurance-based billing together in one system, rather than at hospitals, large enterprise health systems, or practices operating outside the U.S. healthcare and insurance framework, where its billing and coding tools would not directly apply. Practices evaluating it should think of it as one option among several EHR-plus-billing platforms aimed at independent providers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$who-drchrono-is-for$q$, $q$Who DrChrono Is For$q$, 2, ARRAY[$q$DrChrono tends to fit best for solo physicians and small group practices across specialties such as primary care, urgent care, pediatrics, mental and behavioral health, and physical therapy, where having a single vendor handle both clinical charting and medical billing reduces administrative overhead and the number of systems staff need to learn. Growing multi-provider clinics that still operate as a single independent business, rather than as part of a larger health system, are also commonly cited as a good fit.$q$, $q$Physicians who see patients in multiple settings, such as clinic visits, hospital rounds, or house calls, are a natural fit given the platform's mobile app, which lets a provider document a visit, e-prescribe, and check a schedule directly from an iPad or iPhone without needing to return to a desktop workstation between patients. This mobility can matter as much as any single feature for providers whose day does not happen entirely at one desk.$q$, $q$Practices that would rather outsource billing entirely than hire and manage in-house billing staff are also a good match, since DrChrono offers plan tiers that bundle a dedicated revenue cycle management team on top of the core EHR and practice management software, rather than requiring a separate billing vendor and a separate integration project.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Larger hospital systems and multi-facility health networks that need enterprise-grade interoperability, inpatient workflows, or deep integration with an existing hospital IT stack are generally better served by larger enterprise EHR vendors that are purpose-built for that scale and for hospital-based, rather than ambulatory, care. DrChrono is not positioned or marketed as an inpatient or hospital EHR.$q$, $q$Practices located outside the United States may find DrChrono a poor fit, since its billing, coding, and insurance-eligibility verification tools are built around U.S. payer rules and regulatory requirements rather than international healthcare and insurance systems. Practices with highly specialized documentation needs that fall outside DrChrono's template library may also need to weigh how much custom template-building work is required before going live.$q$, $q$Because DrChrono does not publish fixed pricing and requires a sales conversation to get a quote, practices that want fully transparent, self-serve pricing before they engage with a vendor, or that need a genuinely free or very low-cost EHR to start with almost no budget, may be better served by a vendor that advertises flat, published rates up front rather than a custom quote process.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the clinical level, DrChrono offers customizable charting templates by specialty, dictation and speech-to-text support, and e-prescribing that includes electronic prescribing of controlled substances (EPCS), letting a clinician document a visit and send a prescription from within the same patient encounter without switching applications.$q$, $q$On the operational side, the platform includes appointment scheduling, patient check-in, insurance eligibility verification, and medical billing tools, ranging from claim scrubbing and electronic claim submission through to optional full-service revenue cycle management for practices that would rather have billing handled for them by DrChrono's own team.$q$, $q$Patients interact with the practice through the OnPatient portal for online scheduling, secure messaging, digital intake forms, and bill payment, while DrChrono's video visit tools support telehealth appointments; an open API and app marketplace round out the platform for practices that need to connect labs, imaging systems, or other specialty software to their EHR without waiting on a native integration.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', $q$drchrono-experience$q$, $q$The DrChrono Experience$q$, 2, ARRAY[$q$Because DrChrono's charting app was built for iPad from its early days, day-to-day use feels closer to a native tablet app than a typical browser-based form, which many clinicians find faster for point-of-care documentation, particularly when relying on templated notes and quick-tap exam findings during a visit rather than free-text typing.$q$, $q$Onboarding involves configuring templates, fee schedules, and payer connections before go-live, and practices that add the billing and RCM tiers work directly with DrChrono's billing team on claims and denial management rather than handling that work entirely in-house; user reviews describe a real learning curve for administrators setting up templates and reports, even though day-to-day charting is generally described as quick once a practice is fully configured and staff are trained.$q$, $q$Ongoing support and account management vary by plan tier, and since pricing and contract terms are only available by speaking with sales, practices evaluating DrChrono should expect a demo-and-quote process rather than a self-serve signup, with the overall day-to-day experience shaped heavily by which combination of EHR, billing, and outsourced RCM services a practice ultimately chooses to purchase.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('658c8cb8-ea59-4b89-bc57-b008fda4a4bd', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
