INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Visual workflow builder$q$, $q$Build multi-step, branching automations triggered by browsing, cart, and purchase behavior without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Behavioral segmentation$q$, $q$Segment customers in real time using purchase history, browsing activity, order frequency, and customer lifetime value.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Native SMS and email in one workflow$q$, $q$Send email and text messages from the same automation canvas, sequencing across channels based on customer response.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Shopify and WooCommerce integrations$q$, $q$Sync store data including orders, customers, and product catalogs in near real time via native connectors.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Pre-built automation templates$q$, $q$Start from ready-made workflows for abandoned cart recovery, welcome series, win-back campaigns, and post-purchase follow-up.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$On-site popups and forms$q$, $q$Grow email and SMS lists directly on a storefront with customizable opt-in forms and popups.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Revenue attribution reporting$q$, $q$Track which campaigns and workflows are driving actual sales, not just opens and clicks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Open API and sub-accounts$q$, $q$Connect custom tools via API access and manage multiple client or brand accounts from one login.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Deep, e-commerce-specific automation with granular behavioral triggers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$SMS and email run natively in the same workflow rather than as separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Real-time Shopify and WooCommerce data sync powers accurate segmentation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Full feature set available on every paid tier, with no gating of advanced tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Large library of pre-built workflow templates speeds up initial setup$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$No permanently free plan, only a limited-time trial with a low sending cap$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Noticeable learning curve for teams new to marketing automation concepts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Pricing scales with contact count, so costs can rise quickly as a list grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Live chat support is reserved for higher-priced plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Limited value for businesses outside of e-commerce, since segmentation is built around store data$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Does Drip have a free plan?$q$, $q$No, Drip does not offer a permanent free plan. It provides a time-limited free trial with restrictions on email sends and daily campaigns; ongoing use requires a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$What e-commerce platforms does Drip integrate with?$q$, $q$Drip integrates natively with Shopify and WooCommerce, syncing customer, order, and product data in near real time to power its segmentation and automation features.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Does Drip support SMS marketing?$q$, $q$Yes. SMS is built into Drip as a native channel with its own compliance settings, allowing automations to combine email and text messages in a single workflow.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$How is Drip priced?$q$, $q$Drip uses contact-based pricing, with the monthly cost determined by how many contacts are in an account. All published tiers include unlimited email sends and the full feature set.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Is Drip good for beginners?$q$, $q$Drip can be challenging for users new to marketing automation, since its segmentation and workflow builder are more advanced than simple newsletter tools. Pre-built templates help shorten the learning curve.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Abandoned cart recovery for Shopify stores$q$, $q$Automatically trigger a sequence of emails and texts when a shopper adds items to a cart but doesn't complete checkout, recovering revenue that would otherwise be lost.$q$, $q$Shopify merchants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Lifecycle segmentation for WooCommerce brands$q$, $q$Group customers by purchase frequency, order value, and browsing behavior to send more relevant campaigns instead of one-size-fits-all newsletters.$q$, $q$WooCommerce store owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Post-purchase upsell and cross-sell sequences$q$, $q$Follow up after a purchase with targeted product recommendations and replenishment reminders based on what a customer actually bought.$q$, $q$Direct-to-consumer brands$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Coordinated email and SMS campaigns$q$, $q$Run a single automation that messages customers by email first, then follows up by text if there's no response, keeping messaging consistent across channels.$q$, $q$Growing online retailers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$2,500 Contacts$q$, $q$$39/month$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["Unlimited email sends","Full workflow automation","Behavioral segmentation","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$10,000 Contacts$q$, $q$$154/month$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["All core automation and segmentation features","SMS marketing available","Open API access","Live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$30,000 Contacts$q$, $q$$449/month$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["Unlimited sub-accounts","Advanced revenue attribution reporting","Onsite popups and forms","Live chat support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$100,000+ Contacts$q$, $q$$1,199/month or custom$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["Full feature set at scale","Priority support options","Custom contact volume above 100,000","Dedicated onboarding guidance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drip is a marketing automation platform built specifically for e-commerce brands, combining email and SMS messaging with behavioral segmentation and a visual workflow builder. It started in 2013 as a simple email capture and autoresponder tool, was acquired by Leadpages in 2016, and later became an independently run company focused entirely on online retail rather than general-purpose email marketing.$q$, $q$The platform connects directly to store data from Shopify, WooCommerce, and similar platforms, pulling in order history, product catalogs, and browsing behavior in near real time. That data feeds into segments and automated workflows, so a customer who abandons a cart, views a product repeatedly, or crosses a lifetime-value threshold can be routed into a specific, targeted sequence of messages.$q$, $q$Unlike many email tools that treat SMS as an add-on, Drip built texting as a native channel that lives inside the same automation canvas as email. A single workflow can branch across both channels based on customer behavior, which is a core part of Drip's pitch to online stores trying to unify their messaging strategy rather than run separate tools for email and SMS.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$who-drip-is-for$q$, $q$Who Drip Is For$q$, 2, ARRAY[$q$Drip is aimed squarely at online stores, particularly those running on Shopify or WooCommerce, that want to go beyond basic email blasts and into behavior-driven automation. Direct-to-consumer brands with recurring purchase cycles, cart abandonment problems, or a need for post-purchase upsell sequences tend to get the most value from the platform's segmentation and workflow depth.$q$, $q$Marketing teams that already understand customer lifecycle concepts, such as win-back campaigns, browse abandonment, and customer lifetime value tiers, will find Drip's tools map closely to those strategies. It also suits growing stores that have outgrown simpler tools like Mailchimp or Klaviyo's entry tiers and need finer control over triggers and segment logic.$q$, $q$Agencies and consultants managing multiple e-commerce clients are another good fit, since the platform supports multiple sub-accounts and exposes an open API for building custom integrations or reporting on top of the core product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses outside of e-commerce, such as B2B software companies, service providers, or content publishers, are not the intended audience. Drip's segmentation model, reporting, and templates are built around store and order data, so the value proposition weakens quickly for anyone without a transactional storefront feeding it information.$q$, $q$Solo founders or very small stores just starting out with email marketing may find Drip more platform than they need. There is no permanently free plan, only a time-limited trial with a low sending cap, and the automation builder has a real learning curve, so teams wanting a simple newsletter tool with a gentle setup process will likely be better served elsewhere.$q$, $q$Budget-conscious merchants with rapidly growing lists should also weigh the cost curve carefully. Because pricing scales with contact count rather than usage or feature tier, a store's bill can rise significantly as its list grows, even if the merchant doesn't need the more advanced automation features unlocked at every level.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Drip is its visual workflow builder, which lets marketers construct multi-step automations triggered by specific behaviors: a product view, a cart addition, a completed purchase, or a change in customer lifetime value. Workflows can branch and combine conditions, and the platform ships with dozens of pre-built automation templates for common e-commerce scenarios like abandoned cart recovery and post-purchase follow-up.$q$, $q$Segmentation in Drip is built on real-time store data rather than static list uploads, letting teams build audiences from purchase history, browsing activity, order frequency, and engagement signals. SMS sits alongside email as a first-class channel with its own compliance settings and billing, so a single automation can message a customer by email, then follow up by text based on how they respond.$q$, $q$Beyond automation, Drip includes on-site popups and forms for list growth, revenue attribution reporting tied back to specific campaigns and workflows, and an open API for custom integrations. Every published pricing tier includes the full feature set, so smaller stores are not locked out of advanced automation or segmentation capabilities that competitors sometimes reserve for higher-priced plans.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$drip-experience$q$, $q$The Drip Experience$q$, 2, ARRAY[$q$Setting up Drip typically starts with connecting a Shopify or WooCommerce store, which syncs historical orders and the product catalog before enabling behavior-based triggers. New users generally lean on the pre-built workflow templates first, adjusting timing, copy, and conditions rather than building automations from a blank canvas, which shortens the path to a working abandoned-cart or welcome sequence.$q$, $q$The interface rewards familiarity with marketing automation concepts more than plug-and-play simplicity. Multi-branch workflows, nested conditional logic, and detailed segment builders give experienced marketers a lot of room to fine-tune campaigns, but the same depth can feel dense to someone used to simpler email tools.$q$, $q$Ongoing use tends to center on refining segments and workflows as more customer data accumulates, combined with regular review of the revenue attribution reports to see which automations are actually driving sales. Support is available by email on all paid plans, with live chat reserved for higher-tier subscriptions, so response times and hands-on help can vary depending on which plan a store is on.$q$]::text[], 4);
